import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVPrinterTest {

    @Mock
    private Appendable out;

    @Mock
    private CSVFormat format;

    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintln_appendsRecordSeparatorAndSetsNewRecordTrue() throws IOException {
        String recordSeparator = "\n";
        when(format.getRecordSeparator()).thenReturn(recordSeparator);

        // Initially set newRecord to false via reflection to verify it becomes true after println
        setField(printer, "newRecord", false);

        printer.println();

        verify(out).append(recordSeparator);
        assertTrue(getField(printer, "newRecord"));
    }

    // Utility method to set private boolean field 'newRecord'
    private void setField(CSVPrinter printer, String fieldName, boolean value) {
        try {
            var field = CSVPrinter.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            field.set(printer, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Utility method to get private boolean field 'newRecord'
    private boolean getField(CSVPrinter printer, String fieldName) {
        try {
            var field = CSVPrinter.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getBoolean(printer);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
